use Phoenix.Framework, :test
use Phoenix.Routing
use SweetXml

post "/soap/xml", fn(conn) ->
    body = case conn.request_body do
        {:ok, data} -> data
        _ -> raise(:not_found)
    end

    xml = SweetXml.decode(body)
    parsed = SweetXml.xpath(xml, "//soapenv:Envelope")
    {:ok, parsed}
end